package com.hospital.management.controller.prescription;import com.hospital.management.model.*;import com.hospital.management.util.RequestUtil;import javax.servlet.http.*;import java.time.LocalDate;import java.util.*;final class PrescriptionRequest {private PrescriptionRequest(){}static Long id(String v){try{long x=Long.parseLong(v);return x>0?x:null;}catch(Exception e){return null;}}static int number(String v,int d){try{return Integer.parseInt(v);}catch(Exception e){return d;}}static LocalDate date(String v){try{return v==null||v.isBlank()?null:LocalDate.parse(v);}catch(Exception e){return null;}}static AuthenticatedUser user(HttpServletRequest q){HttpSession s=q.getSession(false);Object u=s==null?null:s.getAttribute("authenticatedUser");return u instanceof AuthenticatedUser a?a:null;}static AuditContext audit(HttpServletRequest q){return RequestUtil.buildAuditContext(q);}static PrescriptionForm form(HttpServletRequest q){PrescriptionForm f=new PrescriptionForm();f.setPrescriptionId(id(q.getParameter("prescriptionId")));f.setMedicalRecordId(id(q.getParameter("medicalRecordId")));f.setValidUntil(q.getParameter("validUntil"));f.setNotes(q.getParameter("notes"));f.setStatus(q.getParameter("status"));List<PrescriptionItemForm>x=new ArrayList<>();for(int i=0;i<20;i++){String base="items["+i+"]";String medicine=q.getParameter(base+".medicineName");if(medicine==null)continue;PrescriptionItemForm z=new PrescriptionItemForm();z.setMedicineName(medicine);z.setDosage(q.getParameter(base+".dosage"));z.setFrequency(q.getParameter(base+".frequency"));z.setDuration(q.getParameter(base+".duration"));z.setRoute(q.getParameter(base+".route"));z.setInstructions(q.getParameter(base+".instructions"));x.add(z);}f.setItems(x);return f;}}
